import java.util.ArrayList;
import java.util.Arrays;
import java.util.Comparator;
import java.util.List;

class Interval {
    int start, end;

    Interval(int start, int end) {
        this.start = start;
        this.end = end;
    }
}

public class ScratchPad {
    public static int[][] intervalOR(int[][] l1, int[][] l2) {
        List<Interval> intervals = new ArrayList<>();
        for (int[] interval : l1) {
            intervals.add(new Interval(interval[0], interval[1]));
        }
        for (int[] interval : l2) {
            intervals.add(new Interval(interval[0], interval[1]));
        }

        intervals.sort(Comparator.comparingInt(interval -> interval.start));

        List<Interval> mergedIntervals = new ArrayList<>();
        int i = 0;

        while (i < intervals.size()) {
            int start = intervals.get(i).start;
            int end = intervals.get(i).end;
            while (i < intervals.size() - 1 && end >= intervals.get(i + 1).start) {
                end = Math.max(end, intervals.get(i + 1).end);
                i++;
            }
            mergedIntervals.add(new Interval(start, end));
            i++;
        }

        return getIntArray((List<Interval>) mergedIntervals);
    }

    public static List<Interval> intervalAND(int[][] l1, int[][] l2) {
        List<Interval> intervals1 = new ArrayList<>();
        List<Interval> intervals2 = new ArrayList<>();

        for (int[] interval : l1) {
            intervals1.add(new Interval(interval[0], interval[1]));
        }
        for (int[] interval : l2) {
            intervals2.add(new Interval(interval[0], interval[1]));
        }

        intervals1.sort(Comparator.comparingInt(interval -> interval.start));
        intervals2.sort(Comparator.comparingInt(interval -> interval.start));

        List<Interval> result = new ArrayList<>();
        int i = 0, j = 0;

        while (i < intervals1.size() && j < intervals2.size()) {
            int start1 = intervals1.get(i).start;
            int end1 = intervals1.get(i).end;
            int start2 = intervals2.get(j).start;
            int end2 = intervals2.get(j).end;

            if (end1 < start2) {
                i++;
            } else if (end2 < start1) {
                j++;
            } else {
                int intersectionStart = Math.max(start1, start2);
                int intersectionEnd = Math.min(end1, end2);
                result.add(new Interval(intersectionStart, intersectionEnd));

                if (end1 < end2) {
                    i++;
                } else {
                    j++;
                }
            }
        }

        return result;

    }

    public static int[][] getMergedShifts(List<Interval> shifts) {
        int[] hours = new int[25];
        for (Interval shift : shifts) {
            hours[shift.start]++;
            if(shift.end < 24)
                hours[shift.end + 1]--;
        }

        int ongoingShifts = 0;
        int shiftStart = -1;
        List<Interval> mergedShifts = new ArrayList<>();

        for (int i = 0; i < hours.length; i++) {
            ongoingShifts += hours[i];

            if (ongoingShifts > 0 && shiftStart == -1) {
                shiftStart = i;
            } else if (ongoingShifts == 0 && shiftStart != -1) {
                mergedShifts.add(new Interval(shiftStart, i - 1));
                shiftStart = -1;
            }
        }

        return getIntArray((List<Interval>) mergedShifts);
    }

    private static int[][] getIntArray(List<Interval> mergedShifts) {
        int[][] resultArray = new int[mergedShifts.size()][2];
        for (int k = 0; k < mergedShifts.size(); k++) {
            resultArray[k][0] = mergedShifts.get(k).start;
            resultArray[k][1] = mergedShifts.get(k).end;
        }
        return resultArray;
    }

    public static void main(String[] args) {
        int[][] l1 = {{2, 4}, {6, 8}, {1, 3}};
        int[][] l2 = {{7, 9}, {2, 5}};

        int[][] resultOR = intervalOR(l1, l2);
        int[][] resultAND = getMergedShifts(intervalAND(l1, l2));


        System.out.println("OR => " + Arrays.deepToString(resultOR));
        System.out.println("AND => " + Arrays.deepToString(resultAND));
    }
}
